changeSet.sql:

-- Individual indexes
CREATE INDEX IF NOT EXISTS idx_individual_email ON public.individual(email);
CREATE INDEX IF NOT EXISTS idx_individual_is_active ON public.individual(is_active);

-- Organisation indexes
CREATE INDEX IF NOT EXISTS idx_organisation_name ON public.organisation(name);
CREATE INDEX IF NOT EXISTS idx_organisation_is_active ON public.organisation(is_active);

-- Roles indexes
CREATE INDEX IF NOT EXISTS idx_roles_org_id ON public.roles(org_id);
CREATE INDEX IF NOT EXISTS idx_roles_parent_role_id ON public.roles(parent_role_id);

-- Resource indexes
CREATE INDEX IF NOT EXISTS idx_resource_parent_id ON public.resource(parent_resource_id);
CREATE INDEX IF NOT EXISTS idx_resource_type ON public.resource(type);

-- Individual Role indexes
CREATE INDEX IF NOT EXISTS idx_individual_role_individual_id ON public.individual_role(individual_id);
CREATE INDEX IF NOT EXISTS idx_individual_role_role_id ON public.individual_role(role_id);
CREATE INDEX IF NOT EXISTS idx_individual_role_org_id ON public.individual_role(org_id);

-- Individual Permission indexes
CREATE INDEX IF NOT EXISTS idx_individual_permission_individual_id ON public.individual_permission(individual_id);
CREATE INDEX IF NOT EXISTS idx_individual_permission_org_id ON public.individual_permission(org_id);

-- Session indexes
CREATE INDEX IF NOT EXISTS idx_sessions_individual_id ON public.individual_sessions(individual_id);
CREATE INDEX IF NOT EXISTS idx_sessions_accesstoken ON public.individual_sessions(accesstoken);

-- Audit indexes
CREATE INDEX IF NOT EXISTS idx_password_reset_individual_id ON public.individual_password_reset_audit(individual_id);
CREATE INDEX IF NOT EXISTS idx_password_reset_status ON public.individual_password_reset_audit(reset_status);
CREATE INDEX IF NOT EXISTS idx_verification_contact_value ON public.individual_verification_audit(contact_value);
CREATE INDEX IF NOT EXISTS idx_verification_status ON public.individual_verification_audit(verification_status);

-- Supporting table indexes
CREATE INDEX IF NOT EXISTS idx_list_names_name ON public.list_names(name);
CREATE INDEX IF NOT EXISTS idx_list_values_list_names_id ON public.list_values(list_names_id);
